/**
 * Measures the symmetric leapfrog merge join against the primitive hash join and the generic engine on a two-pattern
 * object join ({@code ?a ex:p1 ?x . ?b ex:p2 ?x}): with the predicates bound, both sides scan a contiguous {@code posc}
 * prefix range ordered on the join object, which is the shape the merge join targets. Overlap sparsity is
 * parameterized: at {@code matchEvery = 1} every dense row matches (the merge join must not regress), at higher strides
 * the next match is far away and the leapfrog's {@code seekForward} pays off. Setup verifies the intended operator
 * actually engaged via its counters, so a silently declined mode fails the run instead of measuring the wrong thing.
 * <p>
 * Note the deliberately avoided anti-shape: a subject join between predicate-bound patterns would force S-ordered
 * {@code spoc} scans with no bound prefix (filtered full-index walks), whose scan cost dwarfs any join strategy —
 * ordering-compatible scans being cheap is a precondition for the merge join to make sense.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class NativeMergeJoinBenchmark {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";

	private static final int DENSE_ROWS = 200_000;

	@Param({ "mergeJoin", "hashJoin", "generic" })
	public String mode;

	@Param({ "1", "32", "1024" })
	public int matchEvery;

	private File dataDir;
	private SailRepository repository;
	private String query;
	private long expectedRows;

	@Setup(Level.Trial)
	public void setUp() {
		System.setProperty(LmdbNativeMergeJoin.MIN_ROWS_PROPERTY, "0");
		System.setProperty(LmdbNativeHashJoin.MIN_ROWS_PROPERTY, "0");
		switch (mode) {
		case "mergeJoin":
			break;
		case "hashJoin":
			System.setProperty(LmdbNativeMergeJoin.ENABLED_PROPERTY, "false");
			break;
		case "generic":
			System.setProperty(NATIVE_FLAG, "false");
			break;
		default:
			throw new IllegalArgumentException(mode);
		}
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI dense = vf.createIRI(EX, "p1");
			IRI sparse = vf.createIRI(EX, "p2");
			conn.begin();
			expectedRows = 0;
			for (int i = 0; i < DENSE_ROWS; i++) {
				IRI joinObject = vf.createIRI(EX, "x" + i);
				conn.add(vf.createIRI(EX, "a" + i), dense, joinObject);
				if (i % matchEvery == 0) {
					conn.add(vf.createIRI(EX, "b" + i), sparse, joinObject);
					expectedRows++;
				}
			}
			conn.commit();
		}
		query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?a ?b ?x WHERE { ?b ex:p2 ?x . ?a ex:p1 ?x }";
		verifyModeEngagement();
	}

	/** One probe run proving the intended join operator actually engages for this mode. */
	private void verifyModeEngagement() {
		LmdbNativeMergeJoin.JOINS.set(0);
		LmdbNativeHashJoin.BUILDS.set(0);
		executeQuery();
		long mergeJoins = LmdbNativeMergeJoin.JOINS.get();
		long hashBuilds = LmdbNativeHashJoin.BUILDS.get();
		boolean engaged;
		switch (mode) {
		case "mergeJoin":
			engaged = mergeJoins > 0 && hashBuilds == 0;
			break;
		case "hashJoin":
			engaged = mergeJoins == 0 && hashBuilds > 0;
			break;
		default:
			engaged = mergeJoins == 0 && hashBuilds == 0;
			break;
		}
		if (!engaged) {
			throw new IllegalStateException(mode + ": unexpected engagement, mergeJoins=" + mergeJoins
					+ " hashBuilds=" + hashBuilds);
		}
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		repository.shutDown();
		FileUtil.deleteDir(dataDir);
		System.clearProperty(NATIVE_FLAG);
		System.clearProperty(LmdbNativeMergeJoin.ENABLED_PROPERTY);
		System.clearProperty(LmdbNativeMergeJoin.MIN_ROWS_PROPERTY);
		System.clearProperty(LmdbNativeHashJoin.MIN_ROWS_PROPERTY);
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			long rows = 0;
			try (TupleQueryResult result = conn.prepareTupleQuery(query).evaluate()) {
				while (result.hasNext()) {
					result.next();
					rows++;
				}
			}
			if (rows != expectedRows) {
				throw new IllegalStateException(mode + ": expected " + expectedRows + " rows but got " + rows);
			}
			return rows;
		}
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("NativeMergeJoinBenchmark")
				.build();
		new Runner(opt).run();
	}
}
